import React from 'react';
import styles from './MessageBubble.module.css';

/**
 * Renders a single chat message bubble.
 * System messages are centered; user messages are left/right aligned.
 */
export default function MessageBubble({ msg, isMine }) {
  if (msg.type === 'SYSTEM' || msg.senderId === 'SYSTEM') {
    return <div className={styles.system}>{msg.message}</div>;
  }

  const time = msg.timestamp
    ? new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    : '';

  return (
    <div className={`${styles.wrapper} ${isMine ? styles.mine : styles.theirs}`}>
      <div className={`${styles.bubble} ${isMine ? styles.bubbleMine : styles.bubbleTheirs}`}>
        <span className={styles.text}>{msg.message}</span>
        <span className={styles.time}>{time}</span>
      </div>
    </div>
  );
}
